import { IMessageComposer } from '@nitrots/nitro-renderer';

/**
* Requests the Name Icon store payload from the server.
* Server should respond with NameIconShopComposer → NameIconShopEvent/Parser.
*/
export class RequestNameIconStoreComposer implements IMessageComposer<[]> {
private _data: [] = [];

constructor() {
// no body needed; header maps to your server's RequestNameIconStoreEvent
console.log('[📤] RequestNameIconStoreComposer → requesting name icon shop');
}

public getMessageArray(): [] {
return this._data;
}

public dispose(): void {
this._data = [] as unknown as [];
}
}
